public function dispatch(array $page, ?Request $request = null): ?Response
    {
        if (! $this->ssrIsEnabled($request ?? request())) {
            return null;
        }

        $isHot = Vite::isRunningHot();

        if (! $isHot && $this->shouldEnsureBundleExists() && ! $this->bundleExists()) {
            return null;
        }

        $url = $isHot
            ? $this->getHotUrl('/__inertia_ssr')
            : $this->getProductionUrl('/render');

        try {
            $response = Http::post($url, $page);

            if ($response->failed()) {
                $this->handleSsrFailure($page, $response->json());

                return null;
            }

            if (! $data = $response->json()) {
                return null;
            }

            return new Response(
                implode("\n", $data['head'] ?? []),
                $data['body'] ?? ''
            );
        } catch (Exception $e) {
            if ($e instanceof StrayRequestException || $e instanceof SsrException) {
                throw $e;
            }

            $this->handleSsrFailure($page, [
                'error' => $e->getMessage(),
                'type' => 'connection',
            ]);

            return null;
        }
    }

public function toResponse($request): Response
    {
        if ($this->component === null) {
            return $this->response;
        }

        $middleware = $this->resolveMiddleware();

        if ($middleware) {
            Inertia::version(fn () => $middleware->version($this->request));
            Inertia::setRootView($this->rootView ?? $middleware->rootView($this->request));
        } elseif ($this->rootView) {
            Inertia::setRootView($this->rootView);
        }

        if ($this->includeSharedData && $middleware) {
            Inertia::share($middleware->share($this->request));

            foreach ($middleware->shareOnce($this->request) as $key => $value) {
                if ($value instanceof OnceProp) {
                    Inertia::share($key, $value);
                } else {
                    Inertia::shareOnce($key, $value);
                }
            }
        }

        return Inertia::render($this->component, $this->props)
            ->toResponse($this->request)
            ->setStatusCode($this->response->getStatusCode());
    }

public function getNavigation(): array
    {
        $items = array_filter(
            $this->items,
            fn (NavigationItem $item): bool => $item->isVisible(),
        );

        return collect($this->groups)
            ->filter(function (NavigationGroup $group): bool {
                $visibleGroupItems = array_filter(
                    $group->getItems(),
                    fn (NavigationItem $item): bool => $item->isVisible(),
                );

                if (empty($visibleGroupItems)) {
                    return false;
                }

                $group->items($visibleGroupItems);

                return true;
            })
            ->when(
                count($items),
                fn (Collection $groups): Collection => $groups->prepend(
                    NavigationGroup::make()->items($items),
                ),
            )
            ->all();
    }

protected function collects()
    {
        $collects = null;

        if (! array_key_exists(static::class, static::$cachedCollectsAttributes)) {
            $attribute = (new ReflectionClass($this))->getAttributes(Collects::class);

            static::$cachedCollectsAttributes[static::class] = $attribute !== []
                ? $attribute[0]->newInstance()->class
                : false;
        }

        if (static::$cachedCollectsAttributes[static::class]) {
            $collects = static::$cachedCollectsAttributes[static::class];
        } elseif ($this->collects) {
            $collects = $this->collects;
        } elseif (str_ends_with(class_basename($this), 'Collection') &&
            (class_exists($class = Str::replaceLast('Collection', '', get_class($this))) ||
             class_exists($class = Str::replaceLast('Collection', 'Resource', get_class($this))))) {
            $collects = $class;
        }

        if (! $collects || is_a($collects, JsonResource::class, true)) {
            return $collects;
        }

        throw new LogicException('Resource collections must collect instances of '.JsonResource::class.'.');
    }

public static function isCallable($var, $syntaxOnly = false)
    {
        if (! is_array($var)) {
            return is_callable($var, $syntaxOnly);
        }

        if (! isset($var[0], $var[1]) || ! is_string($var[1] ?? null)) {
            return false;
        }

        if ($syntaxOnly &&
            (is_string($var[0]) || is_object($var[0])) &&
            is_string($var[1])) {
            return true;
        }

        $class = is_object($var[0]) ? get_class($var[0]) : $var[0];

        $method = $var[1];

        if (! class_exists($class)) {
            return false;
        }

        if (method_exists($class, $method)) {
            return (new ReflectionMethod($class, $method))->isPublic();
        }

        if (is_object($var[0]) && method_exists($class, '__call')) {
            return (new ReflectionMethod($class, '__call'))->isPublic();
        }

        if (! is_object($var[0]) && method_exists($class, '__callStatic')) {
            return (new ReflectionMethod($class, '__callStatic'))->isPublic();
        }

        return false;
    }

protected function collectMergeableMetadata(string $path, Mergeable $prop): void
    {
        if (in_array($path, $this->resetProps)) {
            return;
        }

        if ($this->isPartial && ! $this->isIncludedInPartialMetadata($path)) {
            return;
        }

        if ($prop->shouldDeepMerge()) {
            $this->deepMergeProps[] = $path;
        } elseif ($prop->appendsAtRoot()) {
            $this->mergeProps[] = $path;
        } elseif ($prop->prependsAtRoot()) {
            $this->prependProps[] = $path;
        } else {
            foreach ($prop->appendsAtPaths() as $appendPath) {
                $this->mergeProps[] = "{$path}.{$appendPath}";
            }
            foreach ($prop->prependsAtPaths() as $prependPath) {
                $this->prependProps[] = "{$path}.{$prependPath}";
            }
        }

        foreach ($prop->matchesOn() as $strategy) {
            $this->matchPropsOn[] = "{$path}.{$strategy}";
        }
    }

