public function getAuthorizationResponse(): Response
    {
        if ($this->authorization === null) {
            return $this->getHasActionsLivewire()->getDefaultActionAuthorizationResponse($this) ?? Response::allow();
        }

        if (! is_array($this->authorization)) {
            $response = $this->evaluate($this->authorization);

            return match (true) {
                $response instanceof Response => $response,
                (bool) $response => Response::allow(),
                default => Response::deny(),
            };
        }

        $abilities = $this->authorization['abilities'] ?? [];
        $arguments = $this->parseAuthorizationArguments($this->authorization['arguments'] ?? []);
        $type = $this->authorization['type'] ?? null;

        foreach ($abilities as $ability) {
            $response = Gate::inspect($ability, Arr::wrap($arguments));

            if (($type === 'any') && $response->allowed()) {
                return $response;
            }

            if (($type === 'all') && $response->denied()) {
                return $response;
            }
        }

        return Response::allow();
    }

public function saveUploadedFile(TemporaryUploadedFile $file): ?string
    {
        try {
            if (! $file->exists()) {
                return null;
            }
        } catch (UnableToCheckFileExistence $exception) {
            return null;
        }

        if (
            $this->shouldMoveFiles() &&
            ($this->getDiskName() === (function (): string {
                return $this->disk;
            })->call($file))
        ) {
            $newPath = trim($this->getDirectory() . '/' . $this->getUploadedFileNameForStorage($file), '/');

            $this->getDisk()->move(
                (function (): string {
                    return $this->path;
                })->call($file),
                $newPath,
            );

            return $newPath;
        }

        $path = $file->storeAs(
            $this->getDirectory(),
            $this->getUploadedFileNameForStorage($file),
            $this->getDiskName(),
        );

        if ($this->getVisibility() === 'public') {
            rescue(fn () => $this->getDisk()->setVisibility($path, 'public'), report: false);
        }

        return $path;
    }

public function getUploadedFileAttachment(TemporaryUploadedFile | string | null $attachment = null): ?TemporaryUploadedFile
    {
        if (is_string($attachment)) {
            $attachment = data_get($this->getLivewire(), "componentFileAttachments.{$this->getStatePath()}.{$attachment}");
        } elseif (! $attachment) {
            $attachment = data_get($this->getLivewire(), "componentFileAttachments.{$this->getStatePath()}");
        }

        if ($attachment instanceof TemporaryUploadedFile) {
            $maxSize = $this->getFileAttachmentsMaxSize();
            $acceptedFileTypes = $this->getFileAttachmentsAcceptedFileTypes();

            try {
                Validator::validate(
                    ['file' => $attachment],
                    rules: [
                        'file' => [
                            'file',
                            ...($maxSize ? ["max:{$maxSize}"] : []),
                            ...($acceptedFileTypes ? ['mimetypes:' . implode(',', $acceptedFileTypes)] : []),
                        ],
                    ],
                );
            } catch (ValidationException $exception) {
                return null;
            }
        }

        return $attachment;
    }

