protected function detectCsvEncoding(mixed $resource): ?string
    {
        rewind($resource);

        $lineCount = 0;
        $contentSample = '';

        while ((! feof($resource)) && ($lineCount < 20)) {
            $line = fgets($resource);

            if ($line === false) {
                break;
            }

            $contentSample .= $line;
            $lineCount++;
        }

        // The encoding of a subset should be declared before the encoding of its superset.
        $encodings = [
            'UTF-8',
            'SJIS-win',
            'EUC-KR',
            'ISO-8859-1',
            'GB18030',
            'Windows-1251',
            'Windows-1252',
            'EUC-JP',
        ];

        foreach ($encodings as $encoding) {
            if (! mb_check_encoding($contentSample, $encoding)) {
                continue;
            }

            return $encoding;
        }

        return null;
    }

protected function resolveType(array $schema): array
    {
        $type = $schema['type'] ?? null;
        $nullable = false;

        if (is_array($type)) {
            $nullable = in_array('null', $type, true);

            $names = array_values(array_unique(array_filter(
                $type,
                static fn ($value) => $value !== 'null',
            )));

            if (count($names) > 1) {
                throw new InvalidArgumentException(
                    'Unable to represent a multi-type JSON Schema union ['.implode(', ', array_map('strval', $names)).'].'
                );
            }

            $type = $names[0] ?? null;
        }

        $type ??= $this->inferType($schema);

        if (! is_string($type)) {
            throw new InvalidArgumentException('Unable to determine the JSON Schema type for the given schema.');
        }

        return [$type, $nullable];
    }

static function shouldSkipUpdate($snapshot, $calls): bool
    {
        $id = $snapshot['memo']['id'] ?? null;
        $reactiveProps = $snapshot['memo']['props'] ?? [];

        // Only applies to components with #[Reactive] properties...
        if (empty($reactiveProps)) return false;

        // Only if parent already rendered and stored pending params...
        if (! isset(static::$pendingChildParams[$id])) return false;

        // Don't skip if component also has wire:model bindings...
        if (! empty($snapshot['memo']['bindings'] ?? [])) return false;

        // Don't skip if there are real method calls (not just $commit)...
        foreach ($calls as $call) {
            if (($call['method'] ?? '') !== '$commit') return false;
        }

        $pendingParams = static::$pendingChildParams[$id];

        foreach ($reactiveProps as $propName) {
            $currentValue = $snapshot['data'][$propName] ?? null;
            $newValue = $pendingParams[$propName] ?? null;

            if (! static::valuesMatch($currentValue, $newValue)) {
                return false;
            }
        }

        return true;
    }

