public function handle()
    {
        $this->gatherApplicationInformation();

        (new Collection(static::$data))
            ->map(fn ($items) => (new Collection($items))
                ->map(function ($value) {
                    if (is_array($value)) {
                        return [$value];
                    }

                    if (is_string($value)) {
                        $value = $this->laravel->make($value);
                    }

                    return (new Collection($this->laravel->call($value)))
                        ->map(fn ($value, $key) => [$key, $value])
                        ->values()
                        ->all();
                })->flatten(1)
            )
            ->sortBy(function ($data, $key) {
                $index = array_search($key, ['Environment', 'Cache', 'Drivers']);

                return $index === false ? 99 : $index;
            })
            ->filter(function ($data, $key) {
                return $this->option('only') ? in_array($this->toSearchKeyword($key), $this->sections()) : true;
            })
            ->pipe(fn ($data) => $this->display($data));

        $this->newLine();

        return 0;
    }

protected function addResolveRecordMethodToClass(ClassType $class): void
    {
        $resolutionMode = $this->getResolutionMode();
        $resolutionColumn = $this->getResolutionColumn();

        $method = $class->addMethod('resolveRecord')
            ->setPublic()
            ->setReturnType(match ($resolutionMode) {
                'update' => "?{$this->getModelFqn()}",
                default => $this->getModelFqn(),
            })
            ->setBody(match ($resolutionMode) {
                'upsert' => new Literal(<<<PHP
                    return {$this->simplifyFqn($this->getModelFqn())}::firstOrNew([
                        ? => \$this->data[?],
                    ]);
                    PHP, [$resolutionColumn, $resolutionColumn]),
                'update' => new Literal(<<<PHP
                    return {$this->simplifyFqn($this->getModelFqn())}::query()
                        ->where(?, \$this->data[?])
                        ->first();
                    PHP, [$resolutionColumn, $resolutionColumn]),
                default => <<<PHP
                    return new {$this->simplifyFqn($this->getModelFqn())}();
                    PHP,
            });

        $this->configureResolveRecordMethod($method);
    }

public function get(mixed $state): string | array
    {
        $editor = $this->richEditor->getTipTapEditor()
            ->setContent($state ?? [
                'type' => 'doc',
                'content' => [],
            ]);

        if ($this->richEditor->getFileAttachmentsVisibility() === 'private') {
            $editor->descendants(function (object &$node): void {
                if ($node->type !== 'image') {
                    return;
                }

                if (blank($node->attrs->id ?? null)) {
                    return;
                }

                if (blank($node->attrs->src ?? null)) {
                    return;
                }

                $node->attrs->src = null;
            });
        }

        if ($this->richEditor->getCustomBlocks()) {
            $editor->descendants(function (object &$node): void {
                if ($node->type !== 'customBlock') {
                    return;
                }

                unset($node->attrs->label);
                unset($node->attrs->preview);
                unset($node->attrs->shouldApplyProseStylingToPreview);
            });
        }

        return $editor->{$this->richEditor->isJson() ? 'getDocument' : 'getHtml'}();
    }

